import { Component, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { STAGE_META } from '../../models/models';

@Component({
  selector: 'app-opportunity-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './opportunity-form.component.html',
  styleUrl: './opportunities.css',
})
export class OpportunityFormComponent {
  private fb = inject(FormBuilder);
  private route = inject(ActivatedRoute);
  private router = inject(Router);
  readonly stageMeta = STAGE_META;

  private pm = toSignal(this.route.paramMap, { initialValue: this.route.snapshot.paramMap });
  readonly editId = computed(() => this.pm().get('id'));
  readonly isEdit = computed(() => !!this.editId());

  readonly accounts = ['Acme Corporation', 'Globex Industries', 'Initech', 'Umbrella Health', 'Soylent Foods', 'Stark Energy', 'Wayne Media', 'Hooli Cloud'];

  form = this.fb.group({
    name: ['', [Validators.required]],
    accountName: ['Acme Corporation', [Validators.required]],
    stage: ['PROSPECTING', [Validators.required]],
    amount: [0, [Validators.required, Validators.min(0)]],
    probability: [20, [Validators.min(0), Validators.max(100)]],
    closeDate: ['', [Validators.required]],
  });

  constructor() {
    if (this.isEdit()) {
      this.form.patchValue({
        name: 'Acme — Platform Renewal',
        accountName: 'Acme Corporation',
        stage: 'NEGOTIATION',
        amount: 120000,
        probability: 75,
        closeDate: '2026-08-15',
      });
    }
  }

  save(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    this.router.navigate(this.isEdit() ? ['/opportunities', this.editId()] : ['/opportunities']);
  }
  cancel(): void {
    this.router.navigate(this.isEdit() ? ['/opportunities', this.editId()] : ['/opportunities']);
  }
}
